def run_sequence(steps: list[tuple[str, Callable[[], bool]]], stop_on_failure: bool = {{stop_on_failure}}) -> list[tuple[str, bool]]:
    results: list[tuple[str, bool]] = []
    for name, step in steps:
        passed = step()
        results.append((name, passed))
        if stop_on_failure and not passed:
            break
    return results

